def divide(a, b):
    """Divide two numbers and return the quotient.

    Parameters:
    a (int or float): The numerator.
    b (int or float): The denominator.

    Returns:
    float: The quotient of a and b, or 'undefined' if b is zero.
    """
    if b == 0:
        return 'undefined'
    return a / b

